import{_ as a,a as d,b as t,c as i,d as o,e as n,f as s,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as p,c,a2 as u}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/federated-distributed-index.md","filePath":"ta/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"ta/Other/federated-distributed-index.md"};function b(m,e,f,g,x,q){return p(),c("div",null,[...e[0]||(e[0]=[u('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index பல ImgBed sites ஒன்றுடன் ஒன்று file lists share செய்ய உதவும்.</p><p>எளிமையாக:</p><ul><li>உங்கள் site-இல் selected folders பிறருடன் share செய்யலாம்.</li><li>மற்றொரு node-ல் join செய்து அந்த node-ன் shared file list-ஐ உங்கள் admin panel-க்கு sync செய்யலாம்.</li><li>Federated files browsing, searching, links திறப்பதற்காக. அவை உங்கள் storage-க்கு மீண்டும் upload செய்யப்படாது.</li></ul><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>திறக்கவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>page-ல் மூன்று tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>உங்கள் node enable, public domain confirm, shared folders select, outbound index update</td></tr><tr><td>Nodes I Joined</td><td>நீங்கள் joined ஆன மற்ற ImgBed nodes manage செய்ய</td></tr><tr><td>Nodes Joining Me</td><td>உங்கள் node-ல் join செய்ய விரும்பும் requests manage செய்ய</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Local Node</code> திறக்கவும்.</li><li><code>Enable</code> on செய்யவும்.</li><li><code>Sync folders</code> கீழ் share செய்யும் folders தேர்வு செய்யவும்.</li><li><code>Update Outbound Index</code> கிளிக் செய்யவும்.</li><li>domain change detect செய்தால் current domain சரியானதா confirm செய்து தொடரவும்.</li></ol><p>multiple sync folders தேர்வு செய்யலாம்.</p><p>sync folder list empty என்றால் எல்லா folders share ஆகும்.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>public domain என்பது மற்ற nodes உங்கள் node அணுக பயன்படுத்தும் site URL.</p><p>ImgBed இதை automatically detect செய்கிறது. manual ஆக type செய்ய தேவையில்லை. முதலில் index update செய்யும்போது current access URL production domain தானா என ImgBed கேட்கும்.</p><p>பின்னர் domain மாற்றினால் index update மீண்டும் confirmation கேட்கும்.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders federation nodes-க்கு எந்த files share ஆகும் என்பதை தீர்மானிக்கும்.</p><p>உதாரணமாக நீங்கள் மட்டும் தேர்வு செய்தால்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>மற்ற nodes அந்த இரண்டு directories உள்ள files மட்டும் பார்க்க முடியும்.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>மற்ற nodes உங்களிடமிருந்து sync செய்யும் file list-ஐ இது update செய்கிறது.</p><p>பயன்படுத்த வேண்டிய நேரம்:</p><ul><li>federation முதல் முறையாக enable செய்யும்போது.</li><li>share செய்ய வேண்டிய files upload செய்தபோது.</li><li>sync folders மாற்றும்போது.</li><li>public domain மாற்றி confirm செய்யும்போது.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> என்பது மற்ற nodes-ஐ subscribe செய்யும் இடம்.</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="மற்றொரு-node-க்கு-join-request-அனுப்புதல்" tabindex="-1">மற்றொரு Node-க்கு Join Request அனுப்புதல் <a class="header-anchor" href="#மற்றொரு-node-க்கு-join-request-அனுப்புதல்" aria-label="Permalink to &quot;மற்றொரு Node-க்கு Join Request அனுப்புதல்&quot;">​</a></h3><ol><li>மற்ற owner-இடம் invitation link கேட்கவும்.</li><li>input box-ல் paste செய்யவும்.</li><li><code>Request to Join</code> கிளிக் செய்யவும்.</li><li>மற்ற owner admin panel-ல் approve செய்வதற்காக காத்திருக்கவும்.</li></ol><p>approval பிறகு node status approved ஆகும்.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> joined nodes-இல் இருந்து file lists sync செய்கிறது.</p><p>பயன்படுத்தவும்:</p><ul><li>மற்ற owner உங்கள் request approve செய்த பிறகு.</li><li>shared content update ஆனது என்று மற்ற owner சொன்னால்.</li><li>joined federation file lists அனைத்தையும் refresh செய்ய.</li></ul><p>ஒரு node மட்டும் update செய்ய அந்த node card-ல் <code>Update Index</code> கிளிக் செய்யவும்.</p><p><img src="'+t+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>ஒரு node sync செய்ய வேண்டாம் என்றால் <code>Unsubscribe</code> கிளிக் செய்யவும்.</p><p>unsubscribe செய்த பிறகு அந்த node-ன் federated index local site-இல் இருந்து remove ஆகும்.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> பிறரிடமிருந்து வரும் requests handle செய்யும் இடம்.</p><p><img src="'+i+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-உருவாக்குதல்" tabindex="-1">Invitation Link உருவாக்குதல் <a class="header-anchor" href="#invitation-link-உருவாக்குதல்" aria-label="Permalink to &quot;Invitation Link உருவாக்குதல்&quot;">​</a></h3><ol><li>local node enabled என்பதை உறுதிசெய்யவும்.</li><li>ImgBed public domain confirm செய்ய குறைந்தது ஒருமுறை <code>Update Outbound Index</code> கிளிக் செய்யவும்.</li><li><code>Nodes Joining Me</code> திறக்கவும்.</li><li><code>Reset Invitation Link</code> கிளிக் செய்யவும்.</li><li>invitation link copy செய்து மற்ற owner-க்கு அனுப்பவும்.</li></ol><p>invitation link empty என்றால் public domain இன்னும் confirmed ஆகவில்லை. <code>Local Node</code>-க்கு திரும்பி <code>Update Outbound Index</code> கிளிக் செய்யவும்.</p><h3 id="join-requests-handle-செய்வது" tabindex="-1">Join Requests Handle செய்வது <a class="header-anchor" href="#join-requests-handle-செய்வது" aria-label="Permalink to &quot;Join Requests Handle செய்வது&quot;">​</a></h3><p>யாராவது request submit செய்தால் அது <code>Nodes Joining Me</code> list-ல் தோன்றும்.</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>மற்ற node உங்கள் shared file list sync செய்ய அனுமதி</td></tr><tr><td>Reject</td><td>join request மறுப்பு</td></tr><tr><td>Delete</td><td>முடிந்த record remove</td></tr><tr><td>Check Status</td><td>மற்ற side இன்னும் relationship வைத்திருக்கிறதா என்று check</td></tr></tbody></table><p>approval பிறகு மற்ற side <code>Update Inbound Index</code> கிளிக் செய்தால்தான் உங்கள் shared files அங்கு தெரியும்.</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>relationship approved ஆன பிறகு node card-ல் <code>Message</code> கிளிக் செய்யவும்.</p><p>Messages federation relationship தொடர்பான communication-க்கு மட்டும். files, tags, directories, permissions மாற்றாது.</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="federated-files-பார்க்க" tabindex="-1">Federated Files பார்க்க <a class="header-anchor" href="#federated-files-பார்க்க" aria-label="Permalink to &quot;Federated Files பார்க்க&quot;">​</a></h2><p>sync முடிந்த பிறகு admin file list-க்கு திரும்பவும்.</p><p>page மேல் local files மற்றும் federated files இடையே switch செய்யவும். federated files-ல் synced content browse செய்யலாம்.</p><p>Federated files viewing, searching, preview, links copy ஆகியவற்றுக்காக. அவை local files அல்ல; உங்கள் site-இல் இருந்து move, delete, retag, backup செய்ய முடியாது.</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="relationship-record-இல்லை-என்பதால்-reapply-கேட்கிறது-ஏன்" tabindex="-1">Relationship Record இல்லை என்பதால் Reapply கேட்கிறது ஏன்? <a class="header-anchor" href="#relationship-record-இல்லை-என்பதால்-reapply-கேட்கிறது-ஏன்" aria-label="Permalink to &quot;Relationship Record இல்லை என்பதால் Reapply கேட்கிறது ஏன்?&quot;">​</a></h3><p>பொதுவாக மற்ற side உங்களை delete செய்து record remove செய்திருப்பதாக அர்த்தம். புதிய join request submit செய்யவும்.</p><p><img src="'+l+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="join-செய்த-பிறகு-files-ஏன்-தெரியவில்லை" tabindex="-1">Join செய்த பிறகு Files ஏன் தெரியவில்லை? <a class="header-anchor" href="#join-செய்த-பிறகு-files-ஏன்-தெரியவில்லை" aria-label="Permalink to &quot;Join செய்த பிறகு Files ஏன் தெரியவில்லை?&quot;">​</a></h3><p>சரிபார்க்கவும்:</p><ol><li>மற்ற owner உங்கள் request approve செய்தாரா.</li><li>மற்ற owner <code>Update Outbound Index</code> கிளிக் செய்தாரா.</li><li>நீங்கள் <code>Update Inbound Index</code> கிளிக் செய்தீர்களா.</li><li>மற்ற owner sync folders-ல் share செய்ய வேண்டிய directories உள்ளனவா.</li></ol><h3 id="domain-change-detected-என்றால்-என்ன-செய்ய-வேண்டும்" tabindex="-1">Domain Change Detected என்றால் என்ன செய்ய வேண்டும்? <a class="header-anchor" href="#domain-change-detected-என்றால்-என்ன-செய்ய-வேண்டும்" aria-label="Permalink to &quot;Domain Change Detected என்றால் என்ன செய்ய வேண்டும்?&quot;">​</a></h3><p>production domain மூலம் admin panel திறந்து இருந்தால் confirm செய்து தொடரவும்.</p><p>temporary address பயன்படுத்தினால் cancel செய்து production domain மூலம் admin panel மீண்டும் திறந்து முயற்சி செய்யவும்.</p><h3 id="empty-sync-folder-list-என்றால்-என்ன" tabindex="-1">Empty Sync Folder List என்றால் என்ன? <a class="header-anchor" href="#empty-sync-folder-list-என்றால்-என்ன" aria-label="Permalink to &quot;Empty Sync Folder List என்றால் என்ன?&quot;">​</a></h3><p>sync folder list empty என்றால் எல்லா folders share ஆகும்.</p><p>சில directories மட்டும் share செய்ய வேண்டுமெனில் அவற்றை manually select செய்யவும்.</p><h3 id="outbound-மற்றும்-inbound-index-updates-வித்தியாசம்" tabindex="-1">Outbound மற்றும் Inbound Index Updates வித்தியாசம் <a class="header-anchor" href="#outbound-மற்றும்-inbound-index-updates-வித்தியாசம்" aria-label="Permalink to &quot;Outbound மற்றும் Inbound Index Updates வித்தியாசம்&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>பிறர் என்னிடமிருந்து sync செய்யும் data update</td></tr><tr><td>Update Inbound Index</td><td>நான் பிறரிடமிருந்து sync செய்த data update</td></tr></tbody></table>',78)])])}const _=r(h,[["render",b]]);export{k as __pageData,_ as default};
